// src/api/agents/lifecycle.ts
import { validateUuid as validateUuid2, logger as logger2 } from "@elizaos/core";
import express2 from "express";
function createAgentLifecycleRouter(elizaOS, serverInstance) {
  const router = express2.Router();
  const db = serverInstance.database;
  router.post("/:agentId/start", async (req, res) => {
    const agentId = validateUuid2(req.params.agentId);
    if (!agentId) {
      return sendError(res, 400, "INVALID_ID", "Invalid agent ID format");
    }
    if (!db) {
      return sendError(res, 500, "DB_ERROR", "Database not available");
    }
    try {
      const agent = await db.getAgent(agentId);
      if (!agent) {
        logger2.debug({ src: "http", agentId }, "Agent not found");
        return sendError(res, 404, "NOT_FOUND", "Agent not found");
      }
      const isActive = !!elizaOS.getAgent(agentId);
      if (isActive) {
        logger2.debug({ src: "http", agentId }, "Agent is already running");
        return sendSuccess(res, {
          id: agentId,
          name: agent.name,
          status: "active"
        });
      }
      await serverInstance.startAgents([{ character: agent }]);
      const runtime = elizaOS.getAgent(agentId);
      if (!runtime) {
        throw new Error("Failed to start agent");
      }
      logger2.debug({ src: "http", agentId, agentName: agent.name }, "Agent started");
      sendSuccess(res, {
        id: agentId,
        name: agent.name,
        status: "active"
      });
    } catch (error) {
      logger2.error({ src: "http", agentId, error: error instanceof Error ? error.message : String(error) }, "Error starting agent");
      sendError(res, 500, "START_ERROR", "Error starting agent", error instanceof Error ? error.message : String(error));
    }
  });
  router.post("/:agentId/stop", async (req, res) => {
    const agentId = validateUuid2(req.params.agentId);
    if (!agentId) {
      logger2.debug({ src: "http" }, "Invalid agent ID format");
      return sendError(res, 400, "INVALID_ID", "Invalid agent ID format");
    }
    const runtime = elizaOS.getAgent(agentId);
    if (!runtime) {
      return sendError(res, 404, "NOT_FOUND", "Agent not found");
    }
    await serverInstance?.unregisterAgent(agentId);
    logger2.debug({ src: "http", agentId, agentName: runtime.character.name }, "Agent stopped");
    sendSuccess(res, {
      message: "Agent stopped"
    });
  });
  return router;
}

