// src/middleware/api-key.ts
import { logger as logger13 } from "@elizaos/core";
function apiKeyAuthMiddleware(req, res, next) {
  const apiKeyConfigured = !!process.env.ELIZA_SERVER_AUTH_TOKEN;
  if (!apiKeyConfigured) {
    logger13.debug("[API Key] Not configured - skipping check");
    return next();
  }
  if (req.method === "OPTIONS") {
    return next();
  }
  const apiKey = req.headers?.["x-api-key"];
  if (!apiKey || apiKey !== process.env.ELIZA_SERVER_AUTH_TOKEN) {
    logger13.warn(`[API Key] Unauthorized access attempt from ${req.ip}`);
    return res.status(401).json({
      error: "API key required",
      message: "Missing or invalid X-API-KEY header"
    });
  }
  req.isServerAuthenticated = true;
  logger13.debug("[API Key] Valid - frontend authenticated");
  next();
}
// src/middleware/security.ts
import { logger as logger14 } from "@elizaos/core";
var securityMiddleware = () => {
  return (req, res, next) => {
    res.setHeader("X-Content-Type-Options", "nosniff");
    res.setHeader("X-Frame-Options", "SAMEORIGIN");
    res.setHeader("X-XSS-Protection", "1; mode=block");
    res.setHeader("Referrer-Policy", "no-referrer");
    res.removeHeader("X-Powered-By");
    res.removeHeader("Server");
    const userAgent = req.get("User-Agent");
    const forwarded = req.get("X-Forwarded-For");
    const realIp = req.get("X-Real-IP");
    const clientIp = forwarded || realIp || req.ip;
    if (userAgent && (userAgent.includes("..") || userAgent.includes("<script"))) {
      logger14.warn({ src: "http", ip: clientIp, userAgent }, "Suspicious User-Agent detected");
    }
    const url = req.originalUrl || req.url;
    const queryString = JSON.stringify(req.query);
    const suspiciousIndicators = [
      { pattern: "..", name: "Path traversal" },
      { pattern: "<script", name: "XSS attempt" },
      { pattern: "javascript:", name: "JavaScript injection" }
    ];
    const sqlKeywords = ["union", "select", "drop", "delete", "insert", "update"];
    let hasSqlPattern = false;
    const lowerUrl = url.toLowerCase();
    const lowerQuery = queryString.toLowerCase();
    for (let i = 0;i < sqlKeywords.length - 1; i++) {
      const keyword1 = sqlKeywords[i];
      for (let j = i + 1;j < sqlKeywords.length; j++) {
        const keyword2 = sqlKeywords[j];
        if (lowerUrl.includes(keyword1) && lowerUrl.includes(keyword2) || lowerQuery.includes(keyword1) && lowerQuery.includes(keyword2)) {
          hasSqlPattern = true;
          break;
        }
      }
      if (hasSqlPattern) {
        break;
      }
    }
    for (const indicator of suspiciousIndicators) {
      if (url.includes(indicator.pattern) || queryString.includes(indicator.pattern)) {
        logger14.warn({ src: "http", ip: clientIp, url, pattern: indicator.name }, "Suspicious pattern detected");
        break;
      }
    }
    if (hasSqlPattern) {
      logger14.warn({ src: "http", ip: clientIp, url }, "SQL injection pattern detected");
    }
    next();
  };
};
// src/middleware/rate-limit.ts
import { logger as logger16 } from "@elizaos/core";

// src/api/shared/validation.ts
import { validateUuid as validateUuid12, logger as logger15 } from "@elizaos/core";
var getRuntime = (elizaOS, agentId) => {
  const runtime = elizaOS.getAgent(agentId);
  if (!runtime) {
    throw new Error(`Agent not found: ${agentId}`);
  }
  return runtime;
};
var validateTransport = (value) => {
  if (value === undefined || value === null) {
    return { transport: DEFAULT_TRANSPORT, isValid: true };
  }
  if (typeof value !== "string") {
    return {
      transport: DEFAULT_TRANSPORT,
      isValid: false,
      error: `Invalid transport type "${typeof value}". Transport must be a string.`
    };
  }
  if (TRANSPORT_TYPES.includes(value)) {
    return { transport: value, isValid: true };
  }
  if (value in LEGACY_MODE_MAP) {
    return { transport: LEGACY_MODE_MAP[value], isValid: true };
  }
  const allValid = [...TRANSPORT_TYPES, ...Object.keys(LEGACY_MODE_MAP)];
  return {
    transport: DEFAULT_TRANSPORT,
    isValid: false,
    error: `Invalid transport "${value}". Must be one of: ${[...new Set(allValid)].join(", ")}`
  };
};

