import { validateUuid as validateUuid13, logger as logger17 } from "@elizaos/core";
var validateContentTypeMiddleware = () => {
  return (req, res, next) => {
    if (["POST", "PUT", "PATCH"].includes(req.method)) {
      const contentType = req.get("Content-Type");
      const contentLength = req.get("Content-Length");
      if (!contentLength || contentLength === "0") {
        return next();
      }
      const validTypes = [
        "application/json",
        "multipart/form-data",
        "application/x-www-form-urlencoded"
      ];
      if (!contentType || !validTypes.some((type) => contentType.includes(type))) {
        return sendError(res, 400, "INVALID_CONTENT_TYPE", "Invalid or missing Content-Type header");
      }
    }
    next();
  };
};
// src/api/shared/response-handlers.ts
import { logger as logger18 } from "@elizaos/core";
var SSE_EVENTS = {
  USER_MESSAGE: "user_message",
  CHUNK: "chunk",
  DONE: "done",
  ERROR: "error"
};
function writeSSEEvent(res, event, data) {
  res.write(`event: ${event}
data: ${JSON.stringify(data)}

`);
}
function setupSSEHeaders(res) {
  res.setHeader("Content-Type", "text/event-stream");
  res.setHeader("Cache-Control", "no-cache");
  res.setHeader("Connection", "keep-alive");
  res.flushHeaders();
}
async function handleSSETransport(res, elizaOS, agentId, messageMemory, userMessage) {
  setupSSEHeaders(res);
  writeSSEEvent(res, SSE_EVENTS.USER_MESSAGE, userMessage);
  let chunkIndex = 0;
  try {
    await elizaOS.handleMessage(agentId, messageMemory, {
      onStreamChunk: async (chunk, messageId) => {
        writeSSEEvent(res, SSE_EVENTS.CHUNK, {
          messageId,
          chunk,
          index: chunkIndex++
        });
      },
      onResponse: async (responseContent) => {
        writeSSEEvent(res, SSE_EVENTS.DONE, responseContent);
        res.end();
      },
      onError: async (error) => {
        writeSSEEvent(res, SSE_EVENTS.ERROR, { error: error.message });
        res.end();
      }
    });
  } catch (streamError) {
    writeSSEEvent(res, SSE_EVENTS.ERROR, {
      error: streamError instanceof Error ? streamError.message : String(streamError)
    });
    res.end();
  }
}
async function handleHttpTransport(res, elizaOS, agentId, messageMemory, userMessage, additionalResponseData) {
  try {
    const result = await elizaOS.handleMessage(agentId, messageMemory);
    res.status(201).json({
      success: true,
      userMessage,
      agentResponse: result.processing?.responseContent,
      ...additionalResponseData
    });
  } catch (error) {
    logger18.error({ src: "http", agentId, error }, "Error in HTTP transport message handling");
    res.status(500).json({
      success: false,
      error: "Failed to process message in HTTP transport"
    });
  }
}
function handleWebSocketTransport(res, userMessage, additionalResponseData, onWebSocketTransport) {
  if (onWebSocketTransport) {
    Promise.resolve(onWebSocketTransport()).catch((err) => {
      logger18.error({ src: "http", error: err }, "Error in websocket transport callback");
    });
  }
  res.status(201).json({
    success: true,
    userMessage,
    ...additionalResponseData
  });
}
async function handleTransport(options) {
  const {
    res,
    transport,
    elizaOS,
    agentId,
    messageMemory,
    userMessage,
    additionalResponseData,
    onWebSocketTransport
  } = options;
  switch (transport) {
    case "sse":
      await handleSSETransport(res, elizaOS, agentId, messageMemory, userMessage);
      break;
    case "http":
      await handleHttpTransport(res, elizaOS, agentId, messageMemory, userMessage, additionalResponseData);
      break;
    case "websocket":
    default:
      handleWebSocketTransport(res, userMessage, additionalResponseData, onWebSocketTransport);
      break;
  }
}

