import {
  validateUuid as validateUuid17,
  logger as logger22,
  getContentTypeFromMimeType,
  getUploadsAgentsDir as getUploadsAgentsDir3
} from "@elizaos/core";
import express17 from "express";
import multer3 from "multer";
import fs3 from "fs";
import path5 from "path";
var storage2 = multer3.memoryStorage();
var upload2 = multer3({
  storage: storage2,
  limits: {
    fileSize: MAX_FILE_SIZE,
    files: 1
  },
  fileFilter: (_req, file, cb) => {
    if (ALLOWED_MEDIA_MIME_TYPES.includes(file.mimetype)) {
      cb(null, true);
    } else {
      cb(new Error("Invalid file type"));
    }
  }
});
async function saveUploadedFile(file, agentId) {
  const uploadDir = path5.join(getUploadsAgentsDir3(), agentId);
  if (!fs3.existsSync(uploadDir)) {
    fs3.mkdirSync(uploadDir, { recursive: true });
  }
  const timestamp = Date.now();
  const random = Math.round(Math.random() * 1e9);
  const ext = path5.extname(file.originalname);
  const filename = `${timestamp}-${random}${ext}`;
  const filePath = path5.join(uploadDir, filename);
  fs3.writeFileSync(filePath, file.buffer);
  const url = `/media/uploads/agents/${agentId}/${filename}`;
  return { filename, url };
}
function createAgentMediaRouter() {
  const router = express17.Router();
  router.post("/:agentId/upload-media", upload2.single("file"), async (req, res) => {
    logger22.debug({ src: "http" }, "Processing media upload");
    const agentId = validateUuid17(req.params.agentId);
    if (!agentId) {
      return sendError(res, 400, "INVALID_ID", "Invalid agent ID format");
    }
    if (!req.file) {
      return sendError(res, 400, "INVALID_REQUEST", "No media file provided");
    }
    const mediaType = getContentTypeFromMimeType(req.file.mimetype);
    if (!mediaType) {
      return sendError(res, 400, "UNSUPPORTED_MEDIA_TYPE", `Unsupported media MIME type: ${req.file.mimetype}`);
    }
    try {
      const result = await saveUploadedFile(req.file, agentId);
      logger22.info({
        src: "http",
        path: req.path,
        agentId,
        mediaType,
        filename: result.filename,
        url: result.url
      }, "Successfully uploaded media");
      sendSuccess(res, {
        url: result.url,
        type: mediaType,
        filename: result.filename,
        originalName: req.file.originalname,
        size: req.file.size
      });
    } catch (error) {
      logger22.error({
        src: "http",
        path: req.path,
        agentId,
        error: error instanceof Error ? error.message : String(error)
      }, "Error processing media upload");
      sendError(res, 500, "UPLOAD_ERROR", "Failed to process media upload", error instanceof Error ? error.message : String(error));
    }
  });
  return router;
}

