// src/api/memory/groups.ts
import { validateUuid as validateUuid19, logger as logger24, createUniqueUuid as createUniqueUuid4, ChannelType as ChannelType5 } from "@elizaos/core";
import express20 from "express";
function createGroupMemoryRouter(elizaOS, serverInstance) {
  const router = express20.Router();
  const db = serverInstance?.database;
  router.post("/groups/:messageServerId", async (req, res) => {
    const messageServerId = validateUuid19(req.params.messageServerId);
    const { name, worldId, source, metadata, agentIds = [] } = req.body;
    if (!Array.isArray(agentIds) || agentIds.length === 0) {
      return sendError(res, 400, "BAD_REQUEST", "agentIds must be a non-empty array");
    }
    const results = [];
    const errors = [];
    for (const agentId of agentIds) {
      try {
        const runtime = getRuntime(elizaOS, agentId);
        const roomId = createUniqueUuid4(runtime, messageServerId);
        const roomName = name || `Chat ${new Date().toLocaleString()}`;
        await runtime.ensureWorldExists({
          id: worldId,
          name: source,
          agentId: runtime.agentId,
          messageServerId
        });
        await runtime.ensureRoomExists({
          id: roomId,
          name: roomName,
          source,
          type: ChannelType5.API,
          worldId,
          messageServerId,
          metadata,
          channelId: roomId
        });
        await runtime.addParticipant(runtime.agentId, roomId);
        await runtime.ensureParticipantInRoom(runtime.agentId, roomId);
        await runtime.setParticipantUserState(roomId, runtime.agentId, "FOLLOWED");
        results.push({
          id: roomId,
          name: roomName,
          source: "client",
          worldId,
          type: ChannelType5.API
        });
      } catch (error) {
        logger24.error({
          src: "http",
          path: req.path,
          agentId,
          error: error instanceof Error ? error.message : String(error)
        }, "Error creating room for agent");
        errors.push({
          agentId,
          code: error instanceof Error && error.message === "Agent not found" ? "NOT_FOUND" : "CREATE_ERROR",
          message: error instanceof Error && error.message === "Agent not found" ? error.message : "Failed to Create group",
          details: error instanceof Error ? error.message : String(error)
        });
      }
    }
    if (results.length === 0 && errors.length > 0) {
      res.status(500).json({
        success: false,
        error: errors.length ? errors : [{ code: "UNKNOWN_ERROR", message: "No rooms were created" }]
      });
      return;
    }
    res.status(errors.length ? 207 : 201).json({
      success: errors.length === 0,
      data: results,
      errors: errors.length ? errors : undefined
    });
  });
  router.delete("/groups/:messageServerId", async (req, res) => {
    const worldId = validateUuid19(req.params.messageServerId);
    if (!worldId) {
      return sendError(res, 400, "INVALID_ID", "Invalid messageServerId (worldId) format");
    }
    if (!db) {
      return sendError(res, 500, "DB_ERROR", "Database not available");
    }
    try {
      await db.deleteRoomsByWorldId(worldId);
      res.status(204).send();
    } catch (error) {
      logger24.error({
        src: "http",
        path: req.path,
        worldId,
        error: error instanceof Error ? error.message : String(error)
      }, "Error deleting group");
      sendError(res, 500, "DELETE_ERROR", "Error deleting message server", error instanceof Error ? error.message : String(error));
    }
  });
  router.delete("/groups/:messageServerId/memories", async (req, res) => {
    const worldId = validateUuid19(req.params.messageServerId);
    if (!worldId) {
      return sendError(res, 400, "INVALID_ID", "Invalid messageServerId (worldId) format");
    }
    if (!db) {
      return sendError(res, 500, "DB_ERROR", "Database not available");
    }
    try {
      const memories = await db.getMemoriesByWorldId({ worldId, tableName: "messages" });
      const memoryIds = memories.map((memory) => memory.id);
      if (memoryIds.length > 0) {
        await db.deleteManyMemories(memoryIds);
      }
      res.status(204).send();
    } catch (error) {
      logger24.error({
        src: "http",
        path: req.path,
        worldId,
        error: error instanceof Error ? error.message : String(error)
      }, "Error clearing group memories");
      sendError(res, 500, "DELETE_ERROR", "Error deleting group memories", error instanceof Error ? error.message : String(error));
    }
  });
  return router;
}

