    message_bus_default.on("new_message", this.boundHandleIncomingMessage);
    message_bus_default.on("server_agent_update", this.boundHandleServerAgentUpdate);
    message_bus_default.on("message_deleted", this.boundHandleMessageDeleted);
    message_bus_default.on("channel_cleared", this.boundHandleChannelCleared);
